// Sum Major Credits
export function sumMajorCredits(subject1, subject2) {
    return {
        credits: subject1.credits + subject2.credits,
        __brand: "MajorCredits",
    };
}
// Sum Minor Credits
export function sumMinorCredits(subject1, subject2) {
    return {
        credits: subject1.credits + subject2.credits,
        __brand: "MinorCredits",
    };
}
